import React from 'react';

function App() {
  return (
    <div className="App" style={{ margin: 0, padding: 0 }}>
      <header style={styles.header}>
        <div style={styles.logo}>LOGO</div>
        <nav style={styles.nav}>
          <a href="#advantages" style={styles.link}>Преимущества</a>
          <a href="#photos" style={styles.link}>Фотографии</a>
        </nav>
        <button style={styles.loginButton}>Вход</button>
      </header>
    </div>
  );
}

const styles = {
  header: {
    backgroundColor: '#17191D',
    display: 'flex',
    alignItems: 'center',
    padding: '0 20px',
    height: '64px',
    gap: '20px'
  },
  logo: {
    color: '#fff',
    fontSize: '20px',
    fontWeight: 'bold'
  },
  nav: {
    display: 'flex',
    gap: '20px',
    flex: 1,
    justifyContent: 'center'
  },
  link: {
    color: '#fff',
    textDecoration: 'none',
    fontSize: '16px',
    fontFamily: 'Montserrat, sans-serif'
  },
  loginButton: {
    backgroundColor: '#FF342B',
    color: '#fff',
    border: 'none',
    borderRadius: '8px',
    width: '88px',
    height: '44px',
    fontSize: '16px',
    cursor: 'pointer'
  }
};

export default App;
